 1	import React, { FC, Suspense, useState } from 'react';
 2	import { dump } from 'js-yaml';
 3	
 4	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
 5	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 6	import Loading from '@kubevirt-utils/components/Loading/Loading';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { Modal, ModalVariant, Tab, Tabs } from '@patternfly/react-core';
 9	
10	import YamlAndCLIEditor from '../YamlAndCLIEditor/YamlAndCLIEditor';
11	
12	import { TAB } from './utils/constants';
13	import { getCreateVMVirtctlCommand } from './utils/utils';
14	
15	type YamlAndCLIViewerModalProps = {
16	  isOpen: boolean;
17	  onClose: () => void;
18	  vm: V1VirtualMachine;
19	};
20	
21	const YamlAndCLIViewerModal: FC<YamlAndCLIViewerModalProps> = ({ isOpen, onClose, vm }) => {
22	  const { t } = useKubevirtTranslation();
23	
24	  const [activeTabKey, setActiveTabKey] = useState<TAB>(TAB.YAML);
25	
26	  const { instanceTypeVMState } = useInstanceTypeVMStore();
27	  const { selectedBootableVolume, sshSecretCredentials, vmName } = instanceTypeVMState;
28	
29	  const handleTabClick = (_, tabIndex: TAB) => {
30	    setActiveTabKey(tabIndex);
31	  };
32	
33	  return (
34	    <Modal
35	      isOpen={isOpen}
36	      onClose={onClose}
37	      title={`${activeTabKey} for ${vmName}`}
38	      variant={ModalVariant.large}
39	    >
40	      <Suspense fallback={<Loading />}>
41	        <Tabs activeKey={activeTabKey} onSelect={handleTabClick}>
42	          <Tab eventKey={TAB.YAML} title={t('YAML')}>
43	            <YamlAndCLIEditor code={dump(vm || '')} minHeight={350} />
44	          </Tab>
45	          <Tab eventKey={TAB.CLI} title={t('CLI')}>
46	            <YamlAndCLIEditor
47	              code={getCreateVMVirtctlCommand(
48	                vm,
49	                selectedBootableVolume,
50	                sshSecretCredentials?.sshPubKey,
51	              )}
52	              minHeight={150}
53	            />
54	          </Tab>
55	        </Tabs>
56	      </Suspense>
57	    </Modal>
58	  );
59	};
60	
61	export default YamlAndCLIViewerModal;

